"""
config_manager.py
Persistent storage for Scale Brain firmware.

Files managed on flash:
  config.json      — calibration factor, tare offset, unit preference
  wifi_config.json — WiFi credentials + static IP + mode
  profiles.json    — saved weight profiles (CO2 tanks, etc.)
"""

import json
import os
import time

_CONFIG_FILE   = "config.json"
_WIFI_FILE     = "wifi_config.json"
_PROFILES_FILE = "profiles.json"


def _file_exists(path: str) -> bool:
    try:
        os.stat(path)
        return True
    except OSError:
        return False


def _load_json_dict(path: str, default: dict) -> dict:
    if not _file_exists(path):
        return dict(default)
    try:
        with open(path, "r") as f:
            data = json.load(f)
        if not isinstance(data, dict):
            raise ValueError("not a JSON object")
        merged = dict(default)
        merged.update(data)
        return merged
    except Exception as e:
        print(f"[Config] Failed to load {path}: {e} — using defaults")
        return dict(default)


def _load_json_list(path: str) -> list:
    if not _file_exists(path):
        return []
    try:
        with open(path, "r") as f:
            data = json.load(f)
        if not isinstance(data, list):
            raise ValueError("not a JSON array")
        return data
    except Exception as e:
        print(f"[Config] Failed to load {path}: {e} — returning []")
        return []


def _save_json(path: str, data):
    try:
        with open(path, "w") as f:
            json.dump(data, f)
    except Exception as e:
        print(f"[Config] Failed to save {path}: {e}")


_id_seq = 0

def _make_id(prefix: str) -> str:
    global _id_seq
    _id_seq += 1
    return f"{prefix}_{time.time()}_{_id_seq}"


# ---------------------------------------------------------------------------
# System config (calibration, tare, preferences)
# ---------------------------------------------------------------------------

MAX_SCALES = 2

_DEFAULT_SCALE = {"cal_factor": 1.0, "tare_offset": 0, "label": "", "units": "kg"}

_DEFAULT_CONFIG = {
    "num_scales":    1,
    "keglevel_url":  "",      # e.g. "http://192.168.68.50"
}

_config = None


def _migrate_config(cfg):
    """Migrate old flat cal_factor/tare_offset/units into scales array."""
    if "scales" not in cfg:
        cfg["scales"] = []
    if "cal_factor" in cfg or "tare_offset" in cfg:
        s0 = cfg["scales"][0] if cfg["scales"] else dict(_DEFAULT_SCALE)
        if s0.get("cal_factor", 1.0) == 1.0 and cfg.get("cal_factor", 1.0) != 1.0:
            s0["cal_factor"] = cfg["cal_factor"]
        if s0.get("tare_offset", 0) == 0 and cfg.get("tare_offset", 0) != 0:
            s0["tare_offset"] = cfg["tare_offset"]
        cfg.pop("cal_factor", None)
        cfg.pop("tare_offset", None)
        if cfg["scales"]:
            cfg["scales"][0] = s0
        else:
            cfg["scales"].append(s0)
    # Migrate top-level units into scales[0].units
    if "units" in cfg:
        if cfg["scales"]:
            if cfg["scales"][0].get("units", "kg") == "kg":
                cfg["scales"][0]["units"] = cfg["units"]
        cfg.pop("units", None)
    # Ensure each scale entry has all default fields
    for sc in cfg["scales"]:
        for k, v in _DEFAULT_SCALE.items():
            if k not in sc:
                sc[k] = v
    while len(cfg["scales"]) < MAX_SCALES:
        cfg["scales"].append(dict(_DEFAULT_SCALE))
    if "num_scales" not in cfg:
        cfg["num_scales"] = 1
    return cfg


def load_config() -> dict:
    global _config
    _config = _load_json_dict(_CONFIG_FILE, _DEFAULT_CONFIG)
    _config = _migrate_config(_config)
    s0 = _config["scales"][0]
    print(f"[Config] Loaded: num_scales={_config['num_scales']}  "
          f"scale0_cal={s0.get('cal_factor', 1.0):.4f}")
    return _config


def get_config() -> dict:
    global _config
    if _config is None:
        load_config()
    return _config


def save_config(new_config: dict):
    global _config
    _config = new_config
    _save_json(_CONFIG_FILE, _config)


def update_config(patch: dict):
    cfg = get_config()
    cfg.update(patch)
    save_config(cfg)


def get_scale_config(index: int) -> dict:
    cfg = get_config()
    scales = cfg.get("scales", [])
    if index < len(scales):
        return scales[index]
    return dict(_DEFAULT_SCALE)


def update_scale_config(index: int, patch: dict):
    cfg = get_config()
    while len(cfg["scales"]) <= index:
        cfg["scales"].append(dict(_DEFAULT_SCALE))
    cfg["scales"][index].update(patch)
    save_config(cfg)


# ---------------------------------------------------------------------------
# WiFi credentials
# ---------------------------------------------------------------------------

_wifi = None

def load_wifi() -> dict:
    global _wifi
    _wifi = _load_json_dict(_WIFI_FILE, {
        "ssid": "", "password": "",
        "static_ip": "", "subnet": "", "gateway": "", "dns": "",
        "mode": "",
    })
    return _wifi


def get_wifi() -> dict:
    global _wifi
    if _wifi is None:
        load_wifi()
    return _wifi


def save_wifi(ssid: str, password: str,
              static_ip: str = "", subnet: str = "",
              gateway: str = "", dns: str = "",
              mode: str = "sta"):
    global _wifi
    data = {"ssid": ssid, "password": password,
            "static_ip": static_ip, "subnet": subnet,
            "gateway": gateway, "dns": dns,
            "mode": mode}
    _save_json(_WIFI_FILE, data)
    _wifi = data
    print(f"[Config] WiFi saved for SSID: {ssid}  mode: {mode}")


def save_wifi_mode(mode: str):
    global _wifi
    data = load_wifi()
    data["mode"] = mode
    _save_json(_WIFI_FILE, data)
    _wifi = data
    print(f"[Config] WiFi mode set to: {mode}")


def wifi_configured() -> bool:
    w = get_wifi()
    return w.get("mode") == "ap" or bool(w.get("ssid", "").strip())


def clear_wifi():
    global _wifi
    _wifi = None
    try:
        os.remove(_WIFI_FILE)
        print("[Config] WiFi credentials cleared.")
    except OSError:
        pass


# ---------------------------------------------------------------------------
# Profiles (CO2 tanks, containers, etc.)
# ---------------------------------------------------------------------------

_profiles = None


def load_profiles() -> list:
    global _profiles
    _profiles = _load_json_list(_PROFILES_FILE)
    migrated = False
    for p in _profiles:
        if "co2_monitor" in p:
            if p.pop("co2_monitor", False):
                p.setdefault("gas_type", "co2")
            else:
                p.setdefault("gas_type", "")
            migrated = True
        if "co2_scale" in p:
            p["gas_scale"] = p.pop("co2_scale", 0)
            migrated = True
    if migrated:
        _save_json(_PROFILES_FILE, _profiles)
        print("[Config] Profiles migrated co2_monitor -> gas_type")
    print(f"[Config] Profiles loaded: {len(_profiles)}")
    return _profiles


def get_profiles() -> list:
    global _profiles
    if _profiles is None:
        load_profiles()
    return _profiles


def save_profiles(profiles: list):
    global _profiles
    _profiles = profiles
    _save_json(_PROFILES_FILE, _profiles)


def create_profile(data: dict) -> dict:
    profile = {
        "id":              data.get("id") or _make_id("prof"),
        "name":            data.get("name", "New Profile"),
        "tare_weight_kg":  float(data.get("tare_weight_kg", 0.0)),
        "full_weight_kg":  float(data.get("full_weight_kg", 0.0)),
        "capacity_kg":     float(data.get("capacity_kg", 0.0)),
        "gas_type":        str(data.get("gas_type", "")),
        "gas_scale":       int(data.get("gas_scale", 0)),
    }
    if profile["gas_type"] not in ("", "co2", "n2"):
        profile["gas_type"] = ""
    profiles = get_profiles()
    if profile["gas_type"]:
        for p in profiles:
            if p.get("gas_type") == profile["gas_type"]:
                p["gas_type"] = ""
    profiles.append(profile)
    save_profiles(profiles)
    print(f"[Config] Profile created: {profile['id']} '{profile['name']}'")
    return profile


def update_profile(profile_id: str, data: dict):
    profiles = get_profiles()
    for i, p in enumerate(profiles):
        if p.get("id") == profile_id:
            allowed = ("name", "tare_weight_kg", "full_weight_kg", "capacity_kg",
                        "gas_type", "gas_scale")
            for field in allowed:
                if field in data:
                    val = data[field]
                    if field in ("tare_weight_kg", "full_weight_kg", "capacity_kg"):
                        val = float(val)
                    elif field == "gas_type":
                        val = str(val) if val in ("", "co2", "n2") else ""
                    elif field == "gas_scale":
                        val = int(val)
                    p[field] = val
            gt = p.get("gas_type", "")
            if gt:
                for other in profiles:
                    if other.get("id") != profile_id and other.get("gas_type") == gt:
                        other["gas_type"] = ""
            profiles[i] = p
            save_profiles(profiles)
            return p
    return None


def delete_profile(profile_id: str) -> bool:
    profiles = get_profiles()
    new = [p for p in profiles if p.get("id") != profile_id]
    if len(new) == len(profiles):
        return False
    save_profiles(new)
    print(f"[Config] Profile deleted: {profile_id}")
    return True


def get_profile_by_id(profile_id: str):
    for p in get_profiles():
        if p.get("id") == profile_id:
            return p
    return None

"""
server.py
Scale Brain HTTP server - Microdot-based REST API + static file serving.

Endpoints:
  GET  /                          - serve index.html
  GET  /style.css                 - serve stylesheet
  GET  /app.js                    - serve frontend JS

  GET  /api/weight                - all scales weight data (array)
  POST /api/tare                  - zero a scale { "scale": 0 }
  POST /api/hold                  - toggle hold  { "scale": 0, "active": true }
  POST /api/calibrate             - calibrate    { "scale": 0, "weight_g": 1000 }
  GET  /api/debug                 - raw diagnostics (accepts ?s=0)

  GET  /api/config                - config (num_scales, per-scale units, keglevel_url, wifi, version)
  PUT  /api/config                - update config (keglevel_url, num_scales, scale labels, per-scale units)

  GET  /api/gas                   - CO2 and/or N2 data for KegLevel integration

  GET  /api/profiles              - list saved profiles
  POST /api/profiles              - create profile
  PUT  /api/profiles/<id>         - update profile
  DELETE /api/profiles/<id>       - delete profile

  GET  /api/keglevel/kegs         - proxy: fetch kegs from KegLevel
  PUT  /api/keglevel/kegs/<id>    - proxy: update keg on KegLevel

  POST /api/update                - OTA: write file to flash
  GET  /api/ota/manifest          - OTA: read installed manifest
  PUT  /api/ota/manifest          - OTA: write installed manifest

  POST /api/wifi/reset            - erase WiFi credentials, reboot to portal

  GET  /api/version               - firmware version
"""

import asyncio
import gc
import json
import os
import time
import machine

from microdot import Microdot, Request

Request.max_content_length = 32 * 1024

import config_manager
import scale
from version import FIRMWARE_VERSION, BUILD_DATE

app = Microdot()

_boot_ticks = time.ticks_ms()


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

def _json(data, status=200):
    body = json.dumps(data)
    return body, status, {"Content-Type": "application/json",
                          "Cache-Control": "no-store"}


def _error(msg, status=400):
    return _json({"error": msg}, status)


def _serve_file(filename, content_type):
    for prefix in ("/web/", "/"):
        path = prefix + filename
        try:
            os.stat(path)
            with open(path, "r") as f:
                body = f.read()
            return body, 200, {"Content-Type": content_type,
                               "Cache-Control": "no-cache"}
        except OSError:
            continue
    return _error("Not found", 404)


def _file_exists(path):
    try:
        os.stat(path)
        return True
    except OSError:
        return False


# ---------------------------------------------------------------------------
# Static files
# ---------------------------------------------------------------------------

@app.route("/", methods=["GET"])
async def index(request):
    return _serve_file("index.html", "text/html; charset=utf-8")


@app.route("/style.css", methods=["GET"])
async def css(request):
    return _serve_file("style.css", "text/css; charset=utf-8")


@app.route("/app.js", methods=["GET"])
async def js(request):
    return _serve_file("app.js", "application/javascript; charset=utf-8")


@app.route("/help.html", methods=["GET"])
async def help_page(request):
    return _serve_file("help.html", "text/html; charset=utf-8")


@app.route("/assets/<filename>", methods=["GET"])
async def serve_asset(request, filename):
    safe = filename.replace("..", "").replace("/", "").replace("\\", "")
    _mime = {".gif": "image/gif", ".png": "image/png", ".ico": "image/x-icon"}
    ext = ""
    parts = safe.rsplit(".", 1)
    if len(parts) == 2:
        ext = "." + parts[1]
    ct = _mime.get(ext, "application/octet-stream")
    for prefix in ("/web/assets/", "/assets/"):
        path = prefix + safe
        try:
            os.stat(path)
            with open(path, "rb") as f:
                body = f.read()
            return body, 200, {"Content-Type": ct, "Cache-Control": "public, max-age=3600"}
        except OSError:
            continue
    return _error("Not found", 404)


# ---------------------------------------------------------------------------
# /api/weight
# ---------------------------------------------------------------------------

@app.route("/api/weight", methods=["GET"])
async def get_weight(request):
    return _json({
        "num_scales": scale.get_num_scales(),
        "scales": scale.get_all_weight_data(),
    })


# ---------------------------------------------------------------------------
# /api/tare
# ---------------------------------------------------------------------------

@app.route("/api/tare", methods=["POST"])
async def do_tare(request):
    body = request.json or {}
    idx = int(body.get("scale", 0))
    scale.tare(idx)
    return _json({"status": "ok", "scale": idx})


# ---------------------------------------------------------------------------
# /api/hold
# ---------------------------------------------------------------------------

@app.route("/api/hold", methods=["POST"])
async def do_hold(request):
    body = request.json or {}
    idx = int(body.get("scale", 0))
    active = body.get("active", not scale.get_hold(idx))
    scale.set_hold(active, idx)
    return _json({"status": "ok", "hold": active, "scale": idx})


# ---------------------------------------------------------------------------
# /api/calibrate
# ---------------------------------------------------------------------------

@app.route("/api/calibrate", methods=["POST"])
async def do_calibrate(request):
    body = request.json
    if not body or "weight_g" not in body:
        return _error("Provide weight_g (known weight in grams).")
    weight_g = float(body["weight_g"])
    idx = int(body.get("scale", 0))
    if weight_g <= 0:
        return _error("weight_g must be positive.")
    ok, reason = scale.calibrate(weight_g, idx)
    if not ok:
        return _error("Calibration failed: " + reason)
    sc = config_manager.get_scale_config(idx)
    return _json({"status": "ok", "scale": idx,
                  "cal_factor": sc.get("cal_factor", 1.0)})


# ---------------------------------------------------------------------------
# /api/debug
# ---------------------------------------------------------------------------

@app.route("/api/debug", methods=["GET"])
async def get_debug(request):
    s_param = request.args.get("s", "0") if request.args else "0"
    idx = int(s_param)
    return _json(scale.get_debug_data(idx))


# ---------------------------------------------------------------------------
# /api/config
# ---------------------------------------------------------------------------

@app.route("/api/config", methods=["GET"])
async def get_config(request):
    cfg = config_manager.get_config()
    wifi = config_manager.get_wifi()
    import network
    wlan = network.WLAN(network.STA_IF)
    ip = wlan.ifconfig()[0] if wlan.isconnected() else ""
    scales_info = []
    for sc in cfg.get("scales", []):
        scales_info.append({
            "cal_factor": sc.get("cal_factor", 1.0),
            "label":      sc.get("label", ""),
            "units":      sc.get("units", "kg"),
        })
    return _json({
        "num_scales":    cfg.get("num_scales", 1),
        "scales":        scales_info,
        "keglevel_url":  cfg.get("keglevel_url", ""),
        "version":       FIRMWARE_VERSION,
        "build_date":    BUILD_DATE,
        "uptime_s":      time.ticks_diff(time.ticks_ms(), _boot_ticks) // 1000,
        "wifi_ssid":     wifi.get("ssid", ""),
        "wifi_ip":       ip,
        "wifi_mode":     wifi.get("mode", "sta"),
    })


@app.route("/api/config", methods=["PUT"])
async def put_config(request):
    body = request.json
    if not isinstance(body, dict):
        return _error("Body must be a JSON object.")
    patch = {}
    if "keglevel_url" in body:
        patch["keglevel_url"] = str(body["keglevel_url"]).strip()
    if "num_scales" in body:
        ns = int(body["num_scales"])
        if 1 <= ns <= config_manager.MAX_SCALES:
            patch["num_scales"] = ns
    if patch:
        config_manager.update_config(patch)
    if "scale_units" in body:
        idx = int(body.get("scale_index", 0))
        u = body["scale_units"]
        if u in ("kg", "lb", "lb_oz"):
            config_manager.update_scale_config(idx, {"units": u})
    if "scale_label" in body:
        idx = int(body.get("scale_index", 0))
        config_manager.update_scale_config(idx, {"label": str(body["scale_label"])})
    reboot = body.get("reboot", False)
    if reboot:
        asyncio.create_task(_delayed_reset(1000))
    return _json({"status": "ok", "rebooting": reboot})


# ---------------------------------------------------------------------------
# /api/version
# ---------------------------------------------------------------------------

@app.route("/api/version", methods=["GET"])
async def get_version(request):
    return _json({"version": FIRMWARE_VERSION, "build_date": BUILD_DATE})


# ---------------------------------------------------------------------------
# /api/gas  (CO2 and/or N2)
# ---------------------------------------------------------------------------

def _gas_data(prof):
    """Compute remaining pct/weight for a gas profile."""
    idx = prof.get("gas_scale", 0)
    all_data = scale.get_all_weight_data()
    if idx >= len(all_data):
        return None
    sd = all_data[idx]
    if not sd.get("sensor_ok"):
        return None
    current_kg = sd.get("kg", 0)
    tare_kg = prof.get("tare_weight_kg", 0)
    capacity_kg = prof.get("capacity_kg", 0)
    remaining_kg = max(0, current_kg - tare_kg)
    pct = min(100, max(0, (remaining_kg / capacity_kg) * 100)) if capacity_kg > 0 else 0
    return {
        "available": True,
        "pct": round(pct, 1),
        "remaining_kg": round(remaining_kg, 3),
        "capacity_kg": round(capacity_kg, 3),
        "profile_name": prof.get("name", ""),
    }

@app.route("/api/gas", methods=["GET"])
async def get_gas(request):
    profiles = config_manager.get_profiles()
    result = {}
    for p in profiles:
        gt = p.get("gas_type", "")
        if gt in ("co2", "n2"):
            d = _gas_data(p)
            if d:
                result[gt] = d
    return _json(result)


# ---------------------------------------------------------------------------
# /api/profiles
# ---------------------------------------------------------------------------

@app.route("/api/profiles", methods=["GET"])
async def get_profiles(request):
    return _json(config_manager.get_profiles())


@app.route("/api/profiles", methods=["POST"])
async def create_profile(request):
    body = request.json
    if not isinstance(body, dict):
        return _error("Body must be a JSON object.")
    profile = config_manager.create_profile(body)
    return _json(profile, 201)


@app.route("/api/profiles/<profile_id>", methods=["PUT"])
async def update_profile(request, profile_id):
    body = request.json
    if not isinstance(body, dict):
        return _error("Body must be a JSON object.")
    result = config_manager.update_profile(profile_id, body)
    if result is None:
        return _error("Profile not found.", 404)
    return _json(result)


@app.route("/api/profiles/<profile_id>", methods=["DELETE"])
async def delete_profile(request, profile_id):
    if config_manager.delete_profile(profile_id):
        return _json({"status": "ok"})
    return _error("Profile not found.", 404)


# ---------------------------------------------------------------------------
# /api/keglevel/kegs  -  proxy to KegLevel Pico
# ---------------------------------------------------------------------------

def _http_request(method, url, body=None):
    """Minimal HTTP client for MicroPython (no urequests dependency)."""
    import socket
    proto, _, host_port, *path_parts = url.split("/", 3)
    path = "/" + (path_parts[0] if path_parts else "")
    if ":" in host_port:
        host, port = host_port.split(":", 1)
        port = int(port)
    else:
        host, port = host_port, 80

    addr = socket.getaddrinfo(host, port)[0][-1]
    s = socket.socket()
    s.settimeout(5)
    s.connect(addr)

    payload = json.dumps(body).encode() if body else None
    req = "{} {} HTTP/1.0\r\nHost: {}\r\n".format(method, path, host)
    if payload:
        req += "Content-Type: application/json\r\nContent-Length: {}\r\n".format(len(payload))
    req += "\r\n"
    s.send(req.encode())
    if payload:
        s.send(payload)

    resp = b""
    while True:
        chunk = s.recv(2048)
        if not chunk:
            break
        resp += chunk
    s.close()

    header_end = resp.find(b"\r\n\r\n")
    if header_end < 0:
        raise OSError("Invalid HTTP response")
    status_line = resp[:resp.find(b"\r\n")].decode()
    status_code = int(status_line.split(" ", 2)[1])
    body_bytes = resp[header_end + 4:]
    return status_code, json.loads(body_bytes)


@app.route("/api/keglevel/kegs", methods=["GET"])
async def proxy_list_kegs(request):
    cfg = config_manager.get_config()
    url = cfg.get("keglevel_url", "").rstrip("/")
    if not url:
        return _error("keglevel_url not configured.", 400)
    try:
        code, data = _http_request("GET", url + "/api/kegs")
        return _json(data, code)
    except Exception as e:
        return _error("KegLevel unreachable: " + str(e), 502)


@app.route("/api/keglevel/kegs/<keg_id>", methods=["PUT"])
async def proxy_update_keg(request, keg_id):
    cfg = config_manager.get_config()
    url = cfg.get("keglevel_url", "").rstrip("/")
    if not url:
        return _error("keglevel_url not configured.", 400)
    body = request.json
    if not isinstance(body, dict):
        return _error("Body must be a JSON object.")
    try:
        code, data = _http_request("PUT", url + "/api/kegs/" + keg_id, body)
        return _json(data, code)
    except Exception as e:
        return _error("KegLevel unreachable: " + str(e), 502)


# ---------------------------------------------------------------------------
# /api/update  -  OTA firmware update
# ---------------------------------------------------------------------------

_OTA_MANIFEST = "ota_manifest.json"


@app.route("/api/ota/manifest", methods=["GET"])
async def get_ota_manifest(request):
    if _file_exists(_OTA_MANIFEST):
        try:
            with open(_OTA_MANIFEST, "r") as f:
                return _json(json.load(f))
        except Exception:
            pass
    return _json({})


@app.route("/api/ota/manifest", methods=["PUT"])
async def put_ota_manifest(request):
    try:
        body = request.json
        with open(_OTA_MANIFEST, "w") as f:
            json.dump(body, f)
        return _json({"status": "ok"})
    except Exception as e:
        return _error(str(e))


@app.route("/api/update", methods=["POST"])
async def ota_update(request):
    """Write a file to flash for OTA updates."""
    try:
        gc.collect()
        body = request.json
        if not isinstance(body, dict):
            return _error("Body must be a JSON object.")

        filename = body.get("filename", "").strip().replace("\\", "/")
        content  = body.get("content",  "")
        reboot   = body.get("reboot",   False)
        append   = body.get("append",   False)

        _allowed_ext = (".py", ".html", ".css", ".js")
        if not any(filename.endswith(ext) for ext in _allowed_ext):
            return _error("File type not allowed.")
        if filename.startswith("/") or ".." in filename:
            return _error("Invalid path.")

        if not append and "/" in filename:
            acc = []
            for part in filename.split("/")[:-1]:
                acc.append(part)
                dirpath = "/".join(acc)
                try:
                    os.mkdir(dirpath)
                except OSError:
                    pass

        mode = "a" if append else "w"
        with open(filename, mode) as f:
            f.write(content)

        if not append:
            gz_stale = filename + ".gz"
            if _file_exists(gz_stale):
                try:
                    os.remove(gz_stale)
                except OSError:
                    pass

        print("[OTA] {} {} ({} bytes)".format(
            "Appended" if append else "Written", filename, len(content)))

        if reboot:
            asyncio.create_task(_delayed_reset(1500))

        return _json({"status": "ok", "filename": filename,
                      "bytes": len(content), "rebooting": reboot})
    except Exception as e:
        print("[OTA] Error: {}: {}".format(type(e).__name__, e))
        return _error("{}: {}".format(type(e).__name__, e))


async def _delayed_reset(ms):
    await asyncio.sleep_ms(ms)
    machine.reset()


