/* Scale Brain — Frontend (multi-scale, per-card units/kegs/profiles) */

const KG_TO_LB = 2.20462;
const OTA_MANIFEST_URL =
  'https://raw.githubusercontent.com/keglevelmonitor/keglevelpico/main/ota/scalebrain/manifest.json';
const OTA_BUNDLE_URL =
  'https://raw.githubusercontent.com/keglevelmonitor/keglevelpico/main/ota/scalebrain/bundle.json';
const OTA_CHANGELOG_URL =
  'https://raw.githubusercontent.com/keglevelmonitor/keglevelpico/main/ota/scalebrain/changelog.json';

let cardUnits = ['kg', 'kg'];
let holdStates = [false, false];
let numScales = 1;
let profiles = [];
let selectedProfileIds = ['', ''];
let editingProfileId = null;
let editingProfileScale = 0;
let pollTimer = null;
let connected = false;

let kegs = [];
let selectedKegIds = ['', ''];
let keglevelUrl = '';

let _otaManifest = null;
let _otaBundle = null;
let _lastWifiMode = 'sta';
let _calScaleIndex = 0;

// =========================================================================
// API helpers
// =========================================================================

async function apiFetch(path, opts = {}, timeoutMs = 4000) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const resp = await fetch(path, { ...opts, signal: controller.signal });
    if (!resp.ok) throw new Error('HTTP ' + resp.status);
    return await resp.json();
  } finally {
    clearTimeout(timeout);
  }
}

