}

// =========================================================================
// Weight display (per-card units)
// =========================================================================

function formatWeight(data, scaleIndex) {
  const unit = cardUnits[scaleIndex || 0] || 'kg';
  if (!data.sensor_ok) return { display: '\u2014', unit: '' };
  if (unit === 'kg') return { display: (data.kg || 0).toFixed(2), unit: 'kg' };
  if (unit === 'lb') return { display: (data.lb || 0).toFixed(2), unit: 'lb' };
  const lbOz = data.lb_oz || { lb: 0, oz: 0 };
  return { display: lbOz.lb + ' lb ' + lbOz.oz + ' oz', unit: '' };
}

function updateScaleCard(scaleData) {
  const i = scaleData.index;
  const valEl = document.getElementById('weight-value-' + i);
  const unitEl = document.getElementById('weight-unit-' + i);
  const stableBadge = document.getElementById('stable-badge-' + i);
  const holdBadge = document.getElementById('hold-badge-' + i);
  const holdBtn = document.getElementById('btn-hold-' + i);
  if (!valEl) return;
  const fmt = formatWeight(scaleData, i);
  valEl.textContent = fmt.display;
  unitEl.textContent = fmt.unit;
  stableBadge.classList.toggle('badge-hidden', !scaleData.stable);
  const holdCaptured = scaleData.hold && (scaleData.hold_weight_kg || 0) > 0;
  holdBadge.classList.toggle('badge-hidden', !holdCaptured);
  holdStates[i] = scaleData.hold;
  if (holdBtn) holdBtn.classList.toggle('active', scaleData.hold);
}

// =========================================================================
// Gas cylinder readout (per card)
// =========================================================================

function updateProfileReadout(scaleData, scaleIndex) {
  const readout = document.getElementById('profile-readout-' + scaleIndex);
  if (!readout) return;
  const pid = selectedProfileIds[scaleIndex];
  if (!pid || !scaleData || !scaleData.sensor_ok) {
    readout.classList.add('hidden'); return;
  }
  const prof = profiles.find(p => p.id === pid);
  if (!prof) { readout.classList.add('hidden'); return; }
  readout.classList.remove('hidden');
  const unit = cardUnits[scaleIndex];
  const currentKg = scaleData.kg || 0;
  const tareKg = prof.tare_weight_kg || 0;
  const capacityKg = prof.capacity_kg || 0;
  const remainingKg = Math.max(0, currentKg - tareKg);
  const pct = capacityKg > 0 ? Math.min(100, Math.max(0, (remainingKg / capacityKg) * 100)) : 0;
  let remainStr;
  if (unit === 'kg') {
    remainStr = remainingKg.toFixed(2) + ' kg';
  } else if (unit === 'lb') {
    remainStr = (remainingKg * KG_TO_LB).toFixed(2) + ' lb';
  } else {
    const totalOz = remainingKg * KG_TO_LB * 16;
    remainStr = Math.floor(totalOz / 16) + ' lb ' + Math.round(totalOz % 16) + ' oz';
  }
  document.getElementById('prof-remaining-' + scaleIndex).textContent = remainStr;
  document.getElementById('prof-pct-' + scaleIndex).textContent = pct.toFixed(0) + '%';
  document.getElementById('prof-bar-fill-' + scaleIndex).style.width = pct.toFixed(1) + '%';
}

// =========================================================================
// Polling
// =========================================================================

async function poll() {
  try {
    const data = await apiFetch('/api/weight');
    const scales = data.scales || [];
    scales.forEach(s => {
      updateScaleCard(s);
      updateProfileReadout(s, s.index);
      updateKegReadout(s, s.index);
    });
    updateCalLiveWeight(scales);
    setConnected(true);
  } catch (_) {
    setConnected(false);
  }
}

function startPolling() {
  if (pollTimer) clearInterval(pollTimer);
  poll();
  pollTimer = setInterval(poll, 250);
}

function stopPolling() {
  if (pollTimer) { clearInterval(pollTimer); pollTimer = null; }
}

function setConnected(ok) {
  connected = ok;
  const title = document.getElementById('header-title');
  title.classList.toggle('disconnected', !ok);
}

