    await apiFetch('/api/tare', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ scale: scaleIndex }),
    });
  } catch (_) {}
}

async function doHold(scaleIndex) {
  try {
    await apiFetch('/api/hold', {
      method: 'POST',
