}

// =========================================================================
// Calibration (in Settings)
// =========================================================================

function _calWeightGrams() {
  const calUnit = cardUnits[_calScaleIndex] || 'kg';
  if (calUnit === 'lb_oz') {
    const lb = parseFloat(document.getElementById('cal-weight-lb').value) || 0;
    const oz = parseFloat(document.getElementById('cal-weight-oz').value) || 0;
    return (lb + oz / 16) * 453.592;
  }
  const v = parseFloat(document.getElementById('cal-weight').value);
  if (!v || v <= 0) return 0;
  if (calUnit === 'kg') return v * 1000;
  return v * 453.592;
}

async function doCalibrate() {
  const g = _calWeightGrams();
  if (g <= 0) { alert('Enter a valid calibration weight.'); return; }
  try {
    const result = await apiFetch('/api/calibrate', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ weight_g: g, scale: _calScaleIndex }),
    });
    document.getElementById('cal-factor').textContent =
      'Calibration factor: ' + (result.cal_factor || 0).toFixed(4);
    document.getElementById('cal-weight').value = '';
    document.getElementById('cal-weight-lb').value = '';
    document.getElementById('cal-weight-oz').value = '';
  } catch (e) {
    alert('Calibration failed: ' + (e.message || e));
  }
}

function updateCalLiveWeight(scales) {
  if (_activeSettingsTab !== 'calibration') return;
  const data = scales[_calScaleIndex] || scales[0] || { sensor_ok: false };
  const el = document.getElementById('cal-live-weight');
  const unitEl = document.getElementById('cal-live-unit');
  const badge = document.getElementById('cal-stable-badge');
  if (!data.sensor_ok) {
    el.textContent = '\u2014';
    unitEl.textContent = '';
    badge.classList.add('badge-hidden');
    return;
  }
  const fmt = formatWeight(data, _calScaleIndex);
  el.textContent = fmt.display;
  unitEl.textContent = fmt.unit;
  badge.classList.toggle('badge-hidden', !data.stable);
}

function updateCalFormUnits() {
  const calUnit = cardUnits[_calScaleIndex] || 'kg';
  const singleRow = document.getElementById('cal-row-single');
  const lbozRow = document.getElementById('cal-row-lboz');
  if (calUnit === 'lb_oz') {
    singleRow.classList.add('hidden');
    lbozRow.classList.remove('hidden');
  } else {
    singleRow.classList.remove('hidden');
    lbozRow.classList.add('hidden');
    document.getElementById('cal-unit-label').textContent = calUnit === 'kg' ? 'kg' : 'lb';
  }
}

// =========================================================================
// Unit switching (per card)
// =========================================================================

function setUnit(scaleIndex, unit) {
  cardUnits[scaleIndex] = unit;
  const bar = document.getElementById('unit-bar-' + scaleIndex);
  if (bar) {
    bar.querySelectorAll('.unit-btn').forEach(btn => {
      btn.classList.toggle('active', btn.dataset.unit === unit);
    });
  }
  updateCardFormUnits(scaleIndex);
  updateKegDisplay(scaleIndex);
  apiFetch('/api/config', {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ scale_units: unit, scale_index: scaleIndex }),
  }).catch(() => {});
}

function updateCardFormUnits(scaleIndex) {
  const unit = cardUnits[scaleIndex];
  const label = unit === 'kg' ? 'kg' : 'lb';
  ['prof-full-unit-', 'prof-cap-unit-'].forEach(prefix => {
    const el = document.getElementById(prefix + scaleIndex);
    if (el) el.textContent = label;
  });
  if (_calScaleIndex === scaleIndex) updateCalFormUnits();
}

// =========================================================================
// Gas cylinders CRUD (per card)
// =========================================================================

async function loadProfiles() {
  try {
    profiles = await apiFetch('/api/profiles');
    for (let i = 0; i < 2; i++) renderProfileSelect(i);
  } catch (_) {}
}

function renderProfileSelect(scaleIndex) {
  const sel = document.getElementById('profile-select-' + scaleIndex);
  if (!sel) return;
  const cur = sel.value;
  sel.innerHTML = '<option value="">-- No Cylinder --</option>';
  profiles.forEach(p => {
    const opt = document.createElement('option');
    opt.value = p.id;
    const gt = p.gas_type || '';
    opt.textContent = p.name + (gt === 'co2' ? ' [CO2]' : gt === 'n2' ? ' [N2]' : '');
    sel.appendChild(opt);
  });
  if (cur && profiles.find(p => p.id === cur)) sel.value = cur;
  selectedProfileIds[scaleIndex] = sel.value;
  const readout = document.getElementById('profile-readout-' + scaleIndex);
  if (readout) readout.classList.toggle('hidden', !sel.value);
  if (sel.value) updateGasSelect(scaleIndex);
}

function showProfileForm(profile, scaleIndex) {
  editingProfileId = profile ? profile.id : null;
  editingProfileScale = scaleIndex;
  const unit = cardUnits[scaleIndex];
  const toKgOrLb = kg => unit === 'kg' ? kg : kg * KG_TO_LB;
  document.getElementById('prof-name-' + scaleIndex).value = profile ? profile.name : '';
  document.getElementById('prof-cap-' + scaleIndex).value = profile ? toKgOrLb(profile.capacity_kg).toFixed(3) : '';
  document.getElementById('prof-full-' + scaleIndex).value = profile ? toKgOrLb(profile.full_weight_kg).toFixed(3) : '';
  document.getElementById('profile-form-' + scaleIndex).classList.remove('hidden');
  updateCardFormUnits(scaleIndex);
}

function hideProfileForm(scaleIndex) {
  document.getElementById('profile-form-' + scaleIndex).classList.add('hidden');
  editingProfileId = null;
}

async function saveProfile(scaleIndex) {
  const unit = cardUnits[scaleIndex];
  const fromDisplay = val => {
    const v = parseFloat(val) || 0;
    return unit === 'kg' ? v : v / KG_TO_LB;
  };
  const capacityKg = fromDisplay(document.getElementById('prof-cap-' + scaleIndex).value);
  const fullKg     = fromDisplay(document.getElementById('prof-full-' + scaleIndex).value);
  const data = {
    name:           document.getElementById('prof-name-' + scaleIndex).value.trim() || 'Unnamed',
    tare_weight_kg: Math.max(0, fullKg - capacityKg),
    full_weight_kg: fullKg,
    capacity_kg:    capacityKg,
  };
  try {
    if (editingProfileId && editingProfileScale === scaleIndex) {
      await apiFetch('/api/profiles/' + editingProfileId, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });
    } else {
      await apiFetch('/api/profiles', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });
    }
    hideProfileForm(scaleIndex);
    await loadProfiles();
  } catch (e) { alert('Save failed: ' + (e.message || e)); }
}

async function deleteProfile(scaleIndex) {
  const pid = selectedProfileIds[scaleIndex];
  if (!pid) return;
  const prof = profiles.find(p => p.id === pid);
  if (!confirm('Delete cylinder "' + (prof ? prof.name : '') + '"?')) return;
  try {
    await apiFetch('/api/profiles/' + pid, { method: 'DELETE' });
    selectedProfileIds[scaleIndex] = '';
    await loadProfiles();
  } catch (e) { alert('Delete failed: ' + (e.message || e)); }
}

async function setProfileWeight(scaleIndex) {
  const pid = selectedProfileIds[scaleIndex];
  if (!pid) return;
  try {
    const resp = await apiFetch('/api/weight');
    const s = (resp.scales || [])[scaleIndex];
    if (!s || !s.sensor_ok) { alert('Scale not ready.'); return; }
    const kg = s.kg || 0;
    const prof = profiles.find(p => p.id === pid);
    const capacityKg = prof ? (prof.capacity_kg || 0) : 0;
    const patch = {
      full_weight_kg: kg,
      tare_weight_kg: Math.max(0, kg - capacityKg),
    };
    await apiFetch('/api/profiles/' + pid, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(patch),
    });
    await loadProfiles();
  } catch (e) { alert('Failed: ' + (e.message || e)); }
}

async function setFormFullFromScale(scaleIndex) {
  try {
    const resp = await apiFetch('/api/weight');
    const s = (resp.scales || [])[scaleIndex];
    if (!s || !s.sensor_ok) { alert('Scale not ready.'); return; }
    const kg = s.kg || 0;
    const unit = cardUnits[scaleIndex];
    const display = unit === 'kg' ? kg : kg * KG_TO_LB;
    document.getElementById('prof-full-' + scaleIndex).value = display.toFixed(3);
  } catch (e) { alert('Failed: ' + (e.message || e)); }
}

// =========================================================================
// Gas type selector (per card cylinder)
// =========================================================================

function updateGasSelect(scaleIndex) {
  const pid = selectedProfileIds[scaleIndex];
  const sel = document.getElementById('prof-gas-' + scaleIndex);
  if (!sel || !pid) return;
  const prof = profiles.find(p => p.id === pid);
  const gt = prof ? (prof.gas_type || '') : '';
  const gs = prof ? (prof.gas_scale || 0) : 0;
  sel.value = (gt && gs === scaleIndex) ? gt : '';
}

async function setGasType(scaleIndex) {
  const pid = selectedProfileIds[scaleIndex];
  if (!pid) return;
  const sel = document.getElementById('prof-gas-' + scaleIndex);
  const val = sel ? sel.value : '';
  try {
    await apiFetch('/api/profiles/' + pid, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ gas_type: val, gas_scale: scaleIndex }),
    });
    await loadProfiles();
  } catch (e) { alert('Failed: ' + (e.message || e)); }
}

// =========================================================================
// Kegs (from KegLevel) — per card
// =========================================================================

async function loadKegs() {
  for (let i = 0; i < 2; i++) {
    const statusEl = document.getElementById('keg-status-' + i);
    if (statusEl) statusEl.textContent = 'Loading kegs...';
  }
  try {
    kegs = await apiFetch('/api/keglevel/kegs');
    for (let i = 0; i < 2; i++) {
      const statusEl = document.getElementById('keg-status-' + i);
      if (statusEl) statusEl.textContent = kegs.length + ' keg(s) loaded.';
      renderKegSelect(i);
    }
  } catch (e) {
    const msg = (e.message || '') + '';
    for (let i = 0; i < 2; i++) {
      const statusEl = document.getElementById('keg-status-' + i);
      if (!statusEl) continue;
      if (msg.indexOf('400') >= 0) {
        statusEl.textContent = 'Set KegLevel IP in Settings.';
      } else {
        statusEl.textContent = 'Could not reach KegLevel.';
      }
    }
    kegs = [];
    for (let i = 0; i < 2; i++) renderKegSelect(i);
  }
}

function renderKegSelect(scaleIndex) {
  const sel = document.getElementById('keg-select-' + scaleIndex);
  if (!sel) return;
  const cur = sel.value;
  sel.innerHTML = '<option value="">-- No Keg --</option>';
  kegs.forEach(k => {
    const opt = document.createElement('option');
    opt.value = k.id;
    opt.textContent = k.name || k.title || k.id;
    sel.appendChild(opt);
  });
  if (cur && kegs.find(k => k.id === cur)) sel.value = cur;
  selectedKegIds[scaleIndex] = sel.value;
  const readout = document.getElementById('keg-readout-' + scaleIndex);
  if (readout) readout.classList.toggle('hidden', !sel.value);
  updateKegDisplay(scaleIndex);
}

function updateKegDisplay(scaleIndex) {
  const kid = selectedKegIds[scaleIndex];
  if (!kid) return;
  const keg = kegs.find(k => k.id === kid);
  if (!keg) return;
  const unit = cardUnits[scaleIndex];
  const tare = keg.tare_weight_kg || 0;
  const full = keg.starting_total_weight_kg || 0;
  const tareEl = document.getElementById('keg-tare-val-' + scaleIndex);
  const fullEl = document.getElementById('keg-full-val-' + scaleIndex);
  if (unit === 'kg') {
    if (tareEl) tareEl.textContent = tare.toFixed(2) + ' kg';
    if (fullEl) fullEl.textContent = full.toFixed(2) + ' kg';
  } else {
    if (tareEl) tareEl.textContent = (tare * KG_TO_LB).toFixed(2) + ' lb';
    if (fullEl) fullEl.textContent = (full * KG_TO_LB).toFixed(2) + ' lb';
  }
}

function updateKegReadout(scaleData, scaleIndex) {
  if (!selectedKegIds[scaleIndex] || !scaleData || !scaleData.sensor_ok) return;
}

async function setKegWeight(field, scaleIndex) {
  const kid = selectedKegIds[scaleIndex];
  if (!kid) return;
  const unit = cardUnits[scaleIndex];
  const manualId = field === 'tare' ? 'keg-manual-tare-' + scaleIndex : 'keg-manual-full-' + scaleIndex;
  const manualEl = document.getElementById(manualId);
  const manualVal = manualEl ? parseFloat(manualEl.value) : NaN;

  let kg;
  if (!isNaN(manualVal) && manualVal > 0) {
    kg = unit === 'kg' ? manualVal : manualVal / KG_TO_LB;
    if (manualEl) manualEl.value = '';
  } else {
    try {
      const resp = await apiFetch('/api/weight');
      const s = (resp.scales || [])[scaleIndex];
      if (!s || !s.sensor_ok) { alert('Scale not ready.'); return; }
      kg = s.kg || 0;
    } catch (e) { alert('Failed: ' + (e.message || e)); return; }
  }

  const patch = {};
  if (field === 'tare') {
    patch.tare_weight_kg = kg;
  } else {
    patch.starting_total_weight_kg = kg;
  }
  try {
    await apiFetch('/api/keglevel/kegs/' + kid, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(patch),
    });
    const keg = kegs.find(k => k.id === kid);
    if (keg) Object.assign(keg, patch);
    updateKegDisplay(scaleIndex);
    const lbl = field === 'tare' ? 'Tare' : 'Full';
    const statusEl = document.getElementById('keg-status-' + scaleIndex);
    if (statusEl) statusEl.textContent = lbl + ' weight saved.';
  } catch (e) {
    alert('Failed to update KegLevel: ' + (e.message || e));
  }
}

// =========================================================================
// Settings — System info
// =========================================================================

function _displayIp(url) {
  return (url || '').replace(/^https?:\/\//, '').replace(/\/+$/, '');
}

function _normalizeUrl(ip) {
  ip = ip.replace(/\/+$/, '');
  if (ip && !/^https?:\/\//.test(ip)) ip = 'http://' + ip;
  return ip;
}

function updateApModeNotice(mode) {
  _lastWifiMode = mode || 'sta';
  const isAp = _lastWifiMode === 'ap';
  const notice = document.getElementById('ap-updates-notice');
  if (notice) notice.classList.toggle('hidden', !isAp);
  const header = document.querySelector('.main-header');
  if (header) header.classList.toggle('standalone', isAp);
  const btnWifi = document.getElementById('btn-enable-wifi');
  const btnStandalone = document.getElementById('btn-enable-standalone');
  if (btnWifi) btnWifi.disabled = !isAp;
  if (btnStandalone) btnStandalone.disabled = isAp;
}

async function loadSystemInfo() {
  try {
    const cfg = await apiFetch('/api/config');
    keglevelUrl = cfg.keglevel_url || '';
    document.getElementById('sys-keglevel-url').value = _displayIp(keglevelUrl);
    document.getElementById('sys-ssid').textContent = cfg.wifi_ssid || '--';
    document.getElementById('sys-ip').textContent = cfg.wifi_ip || '--';
    const modeLabel = (cfg.wifi_mode || 'sta') === 'ap' ? 'Standalone' : 'Network';
    document.getElementById('sys-wifi-mode').textContent = modeLabel;
    updateApModeNotice(cfg.wifi_mode);

    const ns = cfg.num_scales || 1;
    const nsSel = document.getElementById('sys-num-scales');
    if (nsSel) nsSel.value = String(ns);
    applyNumScales(ns);

    if (cfg.scales) {
      cfg.scales.forEach((sc, idx) => {
        const lbl = document.getElementById('card-label-' + idx);
        if (lbl && sc.label) lbl.textContent = sc.label;
        if (sc.units) cardUnits[idx] = sc.units;
      });
      for (let i = 0; i < 2; i++) refreshUnitBar(i);
    }
  } catch (_) {}
}

function refreshUnitBar(scaleIndex) {
  const bar = document.getElementById('unit-bar-' + scaleIndex);
  if (!bar) return;
  const unit = cardUnits[scaleIndex];
  bar.querySelectorAll('.unit-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.unit === unit);
  });
  updateCardFormUnits(scaleIndex);
}

async function saveKeglevelUrl() {
  const raw = document.getElementById('sys-keglevel-url').value.trim();
  const url = _normalizeUrl(raw);
  try {
    await apiFetch('/api/config', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ keglevel_url: url }),
    });
    keglevelUrl = url;
    document.getElementById('sys-keglevel-url').value = _displayIp(url);
    document.getElementById('keglevel-url-status').textContent = 'Saved.';
    loadKegs();
  } catch (e) {
    document.getElementById('keglevel-url-status').textContent = 'Save failed: ' + (e.message || e);
  }
}

async function saveNumScales() {
  const nsSel = document.getElementById('sys-num-scales');
  const ns = parseInt(nsSel.value, 10);
  const hint = document.getElementById('num-scales-hint');
  try {
    await apiFetch('/api/config', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ num_scales: ns, reboot: true }),
    });
    hint.textContent = 'Saved. Rebooting...';
    hint.style.color = '#ffa500';
    setTimeout(() => { window.location.reload(); }, 5000);
  } catch (e) {
    hint.textContent = 'Save failed: ' + (e.message || e);
    hint.style.color = '#f44336';
  }
}

