async function loadConfig() {
  try {
    const cfg = await apiFetch('/api/config');
    if (cfg.version) {
      document.getElementById('footer-version').textContent = 'Scale Brain v' + cfg.version;
    }
    const ns = cfg.num_scales || 1;
    applyNumScales(ns);

    if (cfg.scales) {
      cfg.scales.forEach((sc, idx) => {
        const lbl = document.getElementById('card-label-' + idx);
        if (lbl && sc.label) lbl.textContent = sc.label;
        if (sc.units) cardUnits[idx] = sc.units;
        if (idx === 0 && sc.cal_factor) {
          document.getElementById('cal-factor').textContent =
            'Calibration factor: ' + sc.cal_factor.toFixed(4);
        }
      });
      for (let i = 0; i < 2; i++) refreshUnitBar(i);
    }
    keglevelUrl = cfg.keglevel_url || '';
    document.getElementById('sys-keglevel-url').value = _displayIp(keglevelUrl);
    updateApModeNotice(cfg.wifi_mode);
  } catch (_) {}
}

// =========================================================================
// Event wiring
// =========================================================================

document.addEventListener('DOMContentLoaded', () => {
  // Nav
  document.getElementById('btn-nav-scale').addEventListener('click', navigateToScale);
  document.getElementById('btn-nav-settings').addEventListener('click', navigateToSettings);

  // Help
  document.getElementById('btn-help').addEventListener('click', () => {
    let anchor = 'toc';
    const activeNav = document.querySelector('.top-nav .nav-btn.active');
    if (activeNav) {
      const id = activeNav.id;
      if (id === 'btn-nav-scale') {
        anchor = 'scale';
      } else if (id === 'btn-nav-settings') {
        const tab = document.querySelector('.settings-tab-btn.active');
        const t = tab ? tab.dataset.settingsTab : '';
        if (t === 'system') anchor = 'system';
        else if (t === 'calibration') anchor = 'calibration';
        else if (t === 'updates') anchor = 'updates';
        else if (t === 'about') anchor = 'about';
        else anchor = 'system';
      }
    }
    window.open('help.html#' + anchor, '_blank');
  });

  // Settings tabs
  document.querySelectorAll('.settings-tab-btn').forEach(btn => {
    btn.addEventListener('click', () => setActiveSettingsTab(btn.dataset.settingsTab));
  });

  // Per-scale buttons, units, kegs, profiles
  for (let idx = 0; idx < 2; idx++) {
    // Tare / Hold
    const tareBtn = document.getElementById('btn-tare-' + idx);
    const holdBtn = document.getElementById('btn-hold-' + idx);
    if (tareBtn) tareBtn.addEventListener('click', () => doTare(idx));
    if (holdBtn) holdBtn.addEventListener('click', () => doHold(idx));

    // Unit buttons
    const unitBar = document.getElementById('unit-bar-' + idx);
    if (unitBar) {
      unitBar.querySelectorAll('.unit-btn').forEach(btn => {
        btn.addEventListener('click', () => setUnit(idx, btn.dataset.unit));
      });
    }

    // Keg controls
    const kegSel = document.getElementById('keg-select-' + idx);
    if (kegSel) kegSel.addEventListener('change', e => {
      selectedKegIds[idx] = e.target.value;
      const readout = document.getElementById('keg-readout-' + idx);
      if (readout) readout.classList.toggle('hidden', !e.target.value);
      updateKegDisplay(idx);
    });
    const kegRefresh = document.getElementById('btn-keg-refresh-' + idx);
    if (kegRefresh) kegRefresh.addEventListener('click', loadKegs);
    const kegSetTare = document.getElementById('btn-keg-set-tare-' + idx);
    if (kegSetTare) kegSetTare.addEventListener('click', () => setKegWeight('tare', idx));
    const kegSetFull = document.getElementById('btn-keg-set-full-' + idx);
    if (kegSetFull) kegSetFull.addEventListener('click', () => setKegWeight('full', idx));

    // Profile controls
    const profSel = document.getElementById('profile-select-' + idx);
    if (profSel) profSel.addEventListener('change', e => {
      selectedProfileIds[idx] = e.target.value;
      const readout = document.getElementById('profile-readout-' + idx);
      if (readout) readout.classList.toggle('hidden', !e.target.value);
      if (e.target.value) updateGasSelect(idx);
    });
    const profNew = document.getElementById('btn-profile-new-' + idx);
    if (profNew) profNew.addEventListener('click', () => showProfileForm(null, idx));
    const profSave = document.getElementById('btn-profile-save-' + idx);
    if (profSave) profSave.addEventListener('click', () => saveProfile(idx));
    const profCancel = document.getElementById('btn-profile-cancel-' + idx);
    if (profCancel) profCancel.addEventListener('click', () => hideProfileForm(idx));
    const profDelete = document.getElementById('btn-profile-delete-' + idx);
    if (profDelete) profDelete.addEventListener('click', () => deleteProfile(idx));
    const profSetFull = document.getElementById('btn-profile-set-full-' + idx);
    if (profSetFull) profSetFull.addEventListener('click', () => setProfileWeight(idx));
    const gasSel = document.getElementById('prof-gas-' + idx);
    if (gasSel) gasSel.addEventListener('change', () => setGasType(idx));
    const formSetFull = document.getElementById('btn-form-set-full-' + idx);
    if (formSetFull) formSetFull.addEventListener('click', () => setFormFullFromScale(idx));
  }

  // Calibration (in Settings)
  document.getElementById('btn-cal-tare').addEventListener('click', () => doTare(_calScaleIndex));
  document.getElementById('btn-calibrate').addEventListener('click', doCalibrate);
  document.getElementById('btn-calibrate-lboz').addEventListener('click', doCalibrate);
  document.getElementById('cal-scale-select').addEventListener('change', e => {
    _calScaleIndex = parseInt(e.target.value, 10);
    updateCalFormUnits();
  });

  // System settings
  document.getElementById('btn-save-keglevel-url').addEventListener('click', saveKeglevelUrl);
  document.getElementById('sys-num-scales').addEventListener('change', saveNumScales);

  // WiFi mode switch
  document.getElementById('btn-enable-wifi').addEventListener('click', () => {
    document.getElementById('wifi-reset-msg').textContent =
      'This will switch the Pico to Network mode. It will reboot into setup mode where you can enter your WiFi network credentials.';
    document.getElementById('modal-wifi-reset').classList.remove('hidden');
  });
  document.getElementById('btn-enable-standalone').addEventListener('click', () => {
    document.getElementById('wifi-reset-msg').textContent =
      'This will switch the Pico to Standalone mode. It will create its own WiFi network (ScaleBrain). Internet access, firmware updates, and KegLevel integration will not be available.';
    document.getElementById('modal-wifi-reset').classList.remove('hidden');
  });
  document.getElementById('btn-wifi-reset-cancel').addEventListener('click', () => {
    document.getElementById('modal-wifi-reset').classList.add('hidden');
  });
  document.getElementById('btn-wifi-reset-confirm').addEventListener('click', async () => {
    const btn = document.getElementById('btn-wifi-reset-confirm');
    btn.disabled = true;
    btn.textContent = 'Rebooting\u2026';
    try {
      await apiFetch('/api/wifi/reset', { method: 'POST' });
    } catch (_) {}
    document.getElementById('wifi-reset-msg').textContent =
      'Pico is rebooting into setup mode. Connect to the ScaleBrain WiFi network to continue.';
  });

  // Updates
  document.getElementById('btn-check-update').addEventListener('click', checkForUpdates);
  document.getElementById('btn-install-update').addEventListener('click', installUpdate);
  document.getElementById('btn-reload').addEventListener('click', reloadPage);

  // Boot
  loadConfig();
  loadProfiles();
  loadKegs();
  startPolling();
});

/* Scale Brain — dark theme matching KegLevel Brain aesthetic */

* { margin: 0; padding: 0; box-sizing: border-box; }

body {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  background: #121212;
  color: #e0e0e0;
  min-height: 100vh;
}

#app {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
  max-width: 960px;
  margin: 0 auto;
}

/* Header */
.main-header {
  display: flex;
  align-items: center;
  padding: 0 16px;
  height: 50px;
  background: #141414;
  flex-shrink: 0;
}

.header-title {
  font-size: 20px;
  font-weight: 700;
  color: #ffa500;
  transition: color 0.3s;
}

.header-title.disconnected {
  color: #999;
}

/* ------------------------------------------------------------------ */
/* Top navigation bar (matches KegLevel)                              */
/* ------------------------------------------------------------------ */
.top-nav {
  display: flex;
  align-items: center;
  padding: 6px 10px;
  gap: 6px;
  background: #1a1a1a;
  border-bottom: 1px solid #262626;
  flex-shrink: 0;
}

.top-nav .nav-btn {
  flex: 1;
  padding: 8px 4px;
  font-size: 13px;
  font-weight: 700;
  color: #fff;
  background: #252525;
  border: 1px solid #333;
  border-radius: 4px;
  cursor: pointer;
}

.top-nav .nav-btn:hover:not(.active) { background: #333; }

.top-nav .nav-btn.active {
  background: #cc8400;
  color: #1a1a1a;
  border-color: #cc8400;
}

.top-nav .help-btn {
  width: 40px;
  padding: 8px 0;
  font-size: 18px;
  font-weight: 700;
  color: #fff;
  background: #26264d;
  border: 1px solid #333;
  border-radius: 4px;
  cursor: pointer;
}

.top-nav .help-btn:hover {
  background: #333366;
}

/* ------------------------------------------------------------------ */
/* Screens                                                            */
/* ------------------------------------------------------------------ */
.screen { flex: 1; display: flex; flex-direction: column; }
.screen.hidden { display: none !important; }
.hidden { display: none !important; }

/* ------------------------------------------------------------------ */
/* Scale cards row                                                    */
/* ------------------------------------------------------------------ */
.scale-cards-row {
  display: flex;
  flex-direction: column;
}

.multi-scale .scale-cards-row {
  flex-direction: row;
  gap: 0;
}

/* ------------------------------------------------------------------ */
/* Scale cards                                                        */
/* ------------------------------------------------------------------ */
.scale-card {
  position: relative;
}

.multi-scale .scale-card {
  flex: 1;
  min-width: 0;
  border: 1px solid #333;
  border-radius: 10px;
  margin: 8px 6px;
  padding-bottom: 4px;
  background: #161616;
}

.card-label {
  text-align: center;
  font-size: 13px;
  font-weight: 700;
  color: #ffa500;
  letter-spacing: 1px;
  padding: 10px 16px 0;
}

.multi-scale .scale-card .weight-section { padding-top: 10px; }

.multi-scale .scale-card .weight-value { font-size: 40px; }

.multi-scale .scale-card .action-bar { padding: 8px 12px 8px; }

.multi-scale .scale-card .unit-bar { padding: 4px 12px 8px; }

.multi-scale .scale-card .card-panel { padding: 12px; }

.multi-scale .scale-card .card-panel .panel-title { font-size: 14px; margin-bottom: 8px; }

.multi-scale .scale-card .profile-controls select { font-size: 13px; padding: 8px; }
.multi-scale .scale-card .profile-btn { font-size: 12px; padding: 8px 10px; }

/* ------------------------------------------------------------------ */
/* Weight display                                                     */
/* ------------------------------------------------------------------ */
.weight-section {
  text-align: center;
  padding: 30px 20px 10px;
  position: relative;
}

.weight-value {
  font-size: 64px;
  font-weight: 300;
  font-variant-numeric: tabular-nums;
  line-height: 1;
  color: #fff;
  letter-spacing: -1px;
}

.weight-unit-row {
  display: flex;
  align-items: center;
  justify-content: center;
  margin-top: 4px;
  min-height: 24px;
}

.weight-unit {
  font-size: 20px;
  color: #888;
}

.weight-badges {
  position: absolute;
  right: 20px;
  display: flex;
  gap: 6px;
}

.stability-badge,
.hold-badge {
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 1px;
  padding: 3px 10px;
  border-radius: 4px;
}

.badge-hidden { visibility: hidden; }

.stability-badge { background: #1b5e20; color: #4caf50; }
.hold-badge { background: #4a1400; color: #ff9800; }

/* ------------------------------------------------------------------ */
/* Action buttons                                                     */
/* ------------------------------------------------------------------ */
.action-bar {
  display: flex;
  gap: 12px;
  padding: 20px 20px 12px;
}

.action-btn {
  flex: 1;
  padding: 14px;
  font-size: 16px;
  font-weight: 700;
  letter-spacing: 1px;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  background: #2a2a2a;
  color: #e0e0e0;
  transition: background 0.15s;
}

.action-btn:hover { background: #3a3a3a; }
.action-btn:active { background: #444; }
.action-btn.active { background: #ffa500; color: #1e1e1e; }

/* ------------------------------------------------------------------ */
/* Unit selector                                                      */
/* ------------------------------------------------------------------ */
.unit-bar {
  display: flex;
  gap: 8px;
  padding: 8px 20px 20px;
}

.unit-btn {
  flex: 1;
  padding: 10px;
  font-size: 14px;
  font-weight: 600;
  border: 1px solid #333;
  border-radius: 6px;
  cursor: pointer;
  background: #1a1a1a;
  color: #888;
  transition: all 0.15s;
}

.unit-btn:hover { border-color: #555; color: #ccc; }
.unit-btn.active { background: #2a2a2a; border-color: #ffa500; color: #ffa500; }

/* ------------------------------------------------------------------ */
/* Panels (kegs, profiles)                                            */
/* ------------------------------------------------------------------ */
.panel {
  padding: 20px;
  border-top: 1px solid #222;
}

.panel-title {
  font-size: 16px;
  font-weight: 700;
  color: #ffa500;
  margin-bottom: 12px;
}

.panel-note {
  font-size: 13px;
  color: #777;
  line-height: 1.6;
  margin-bottom: 14px;
}

/* ------------------------------------------------------------------ */
/* Calibration                                                        */
/* ------------------------------------------------------------------ */
.cal-live-weight {
  display: flex;
  align-items: baseline;
  justify-content: center;
  gap: 8px;
  padding: 16px 0 8px;
}

.cal-live-value {
  font-size: 36px;
  font-weight: 300;
  font-variant-numeric: tabular-nums;
  color: #fff;
}

.cal-live-unit {
  font-size: 16px;
  color: #888;
}

.cal-tare-row {
  display: flex;
  justify-content: center;
  padding: 0 0 16px;
}

.cal-tare-row .action-btn {
  width: 120px;
  flex: none;
}

.cal-row { display: flex; gap: 10px; align-items: center; }

.cal-row input {
  flex: 1;
  padding: 10px 12px;
  font-size: 14px;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 6px;
  color: #e0e0e0;
}

.cal-btn {
  padding: 10px 18px;
  font-size: 13px;
  font-weight: 700;
  letter-spacing: 0.5px;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  background: #ffa500;
  color: #1e1e1e;
  white-space: nowrap;
}

.cal-btn:hover { background: #ffb833; }
.cal-unit-label { font-size: 14px; color: #888; min-width: 20px; }
.cal-input-sm { width: 70px !important; flex: 0 0 70px !important; }
.cal-factor { font-size: 12px; color: #555; margin-top: 8px; }

/* ------------------------------------------------------------------ */
/* Profiles & Kegs shared controls                                    */
/* ------------------------------------------------------------------ */
.profile-controls, .keg-controls {
  display: flex;
  gap: 10px;
  margin-bottom: 14px;
}

.profile-controls select, .keg-controls select {
  flex: 1;
  padding: 10px 12px;
  font-size: 14px;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 6px;
  color: #e0e0e0;
}

.profile-btn {
  padding: 10px 16px;
  font-size: 13px;
  font-weight: 700;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  background: #2a2a2a;
  color: #e0e0e0;
  white-space: nowrap;
}

.profile-btn:hover { background: #3a3a3a; }
.profile-btn.small { font-size: 12px; padding: 8px 12px; }
.profile-btn.red { color: #f44336; }
.profile-btn.outline { background: transparent; border: 1px solid #444; color: #aaa; }
.profile-btn.outline:hover { border-color: #666; }

/* Profile / Keg readout */
.profile-readout, .keg-readout {
  background: #1a1a1a;
  border-radius: 8px;
  padding: 16px;
  margin-bottom: 12px;
}

.readout-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 8px;
}

.readout-label { font-size: 13px; color: #888; }
.readout-value { font-size: 18px; font-weight: 600; color: #fff; font-variant-numeric: tabular-nums; }

.readout-bar {
  width: 100%;
  height: 8px;
  background: #333;
  border-radius: 4px;
  overflow: hidden;
  margin: 8px 0 14px;
}

.readout-bar-fill {
  height: 100%;
  background: #ffa500;
  border-radius: 4px;
  transition: width 0.3s ease;
  width: 0%;
}

.profile-actions, .keg-actions {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

/* Profile form */
.profile-form label {
  display: block;
  font-size: 13px;
  color: #888;
  margin: 12px 0 4px;
}

.profile-form input {
  width: 100%;
  padding: 10px 12px;
  font-size: 14px;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 6px;
  color: #e0e0e0;
}

.form-input-row {
  display: flex;
  gap: 8px;
  align-items: center;
}

.form-input-row input { flex: 1; }

.form-actions {
  display: flex;
  gap: 10px;
  margin-top: 16px;
}

.form-actions button { flex: 1; }

/* Keg status */
.keg-status {
  font-size: 12px;
  color: #777;
  margin-bottom: 8px;
}

/* ------------------------------------------------------------------ */
/* Settings screen (matches KegLevel)                                 */
/* ------------------------------------------------------------------ */
.settings-header {
  padding: 16px;
  background: #141414;
  border-bottom: 1px solid #222;
}

.settings-header h2 {
  margin: 0;
  font-size: 20px;
  font-weight: 700;
  color: #ffa500;
}

.settings-tabs {
  display: flex;
  gap: 4px;
  padding: 10px 16px;
  background: #1a1a1a;
  flex-wrap: wrap;
}

.settings-tab-btn {
  padding: 10px 16px;
  font-size: 14px;
  font-weight: 700;
  color: #888;
  background: #252525;
  border: 1px solid #333;
  border-radius: 4px;
  cursor: pointer;
}

.settings-tab-btn:hover { color: #ccc; background: #333; }

.settings-tab-btn.active {
  color: #ffa500;
  background: #1a1a1a;
  border-color: #ffa500;
}

.settings-content {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
}

.settings-pane { display: none; }
.settings-pane.active { display: block; }

/* System section rows */
.system-section {
  margin-bottom: 24px;
}

.system-section h3 {
  margin: 0 0 12px 0;
  font-size: 16px;
  color: #ffa500;
}

.system-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 0;
  border-bottom: 1px solid #1e1e1e;
}

.system-label { font-size: 13px; color: #888; }
.system-value { font-size: 14px; color: #e0e0e0; font-variant-numeric: tabular-nums; }

.system-field-label {
  display: block;
  font-size: 13px;
  color: #888;
  margin: 12px 0 4px;
}

.system-input-row {
  display: flex;
  gap: 10px;
}

.system-input-row input {
  flex: 1;
  padding: 10px 12px;
  font-size: 14px;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 6px;
  color: #e0e0e0;
}

.system-hint {
  font-size: 12px;
  color: #555;
  margin-top: 4px;
}

.system-select {
  padding: 8px 12px;
  font-size: 14px;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 6px;
  color: #e0e0e0;
}

.cal-scale-row {
  margin-bottom: 12px;
}

.cal-scale-row select {
  width: 100%;
  margin-top: 4px;
}

/* What's new */
.whats-new {
  background: #1a1a1a;
  border-radius: 8px;
  padding: 12px 16px;
  margin: 12px 0;
}

.whats-new-title {
  font-size: 13px;
  font-weight: 700;
  color: #ffa500;
  margin-bottom: 8px;
}

.whats-new-entry {
  padding: 4px 0;
  border-bottom: 1px solid #222;
}

.whats-new-entry:last-child { border-bottom: none; }

.whats-new-ver {
  font-size: 12px;
  font-weight: 700;
  color: #ccc;
}

.whats-new-notes {
  font-size: 13px;
  color: #aaa;
  line-height: 1.4;
  margin-top: 2px;
}

/* Update actions */
.update-actions {
  display: flex;
  gap: 10px;
  margin: 12px 0;
}

.update-btn-reload {
  padding: 10px 16px;
  font-size: 13px;
  font-weight: 700;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  background: #f59e0b;
  color: #1a1a1a;
  white-space: nowrap;
}

.update-btn-reload:hover:not(:disabled) { background: #fbbf24; }
.update-btn-reload:disabled { opacity: 0.5; cursor: not-allowed; }

.update-status {
  font-size: 13px;
  color: #888;
  margin-top: 8px;
}

.update-progress-text {
  font-size: 12px;
  color: #888;
  margin-top: 4px;
  text-align: center;
}

/* Changelog */
.changelog-list {
  max-height: 300px;
  overflow-y: auto;
}

.changelog-entry {
  padding: 8px 0;
  border-bottom: 1px solid #1e1e1e;
}

.changelog-entry-header {
  display: flex;
  justify-content: space-between;
  margin-bottom: 4px;
}

.changelog-ver { font-size: 13px; font-weight: 700; color: #ffa500; }
.changelog-date { font-size: 12px; color: #555; }
.changelog-notes { font-size: 13px; color: #aaa; line-height: 1.5; }

/* ------------------------------------------------------------------ */
/* About section                                                      */
/* ------------------------------------------------------------------ */
.about-section { margin-bottom: 24px; }

.about-support-row {
  display: flex;
  align-items: flex-start;
  gap: 24px;
}

.about-support-row > div { flex: 1; min-width: 0; }

.about-support-img {
  width: 140px;
  height: 140px;
  object-fit: contain;
  flex-shrink: 0;
}

.about-section h3 {
  margin: 0 0 8px 0;
  font-size: 16px;
  color: #ffa500;
}

.about-section p {
  margin: 0;
  font-size: 14px;
  color: #ccc;
  line-height: 1.5;
}

.about-section a { color: #93c5fd; text-decoration: none; }
.about-section a:hover { text-decoration: underline; }

/* ------------------------------------------------------------------ */
/* Modal                                                              */
/* ------------------------------------------------------------------ */
.modal {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
}

.modal.hidden { display: none; }

.modal-content {
  position: relative;
  background: #1a1a1a;
  border: 1px solid #444;
  border-radius: 10px;
  padding: 24px;
  width: 90%;
  max-width: 400px;
}

.modal-confirm p {
  margin: 0 0 20px 0;
  color: #e0e0e0;
}

.modal-actions {
  display: flex;
  gap: 12px;
  justify-content: flex-end;
  margin-top: 20px;
}

.modal-actions .btn-cancel,
.modal-actions .btn-delete {
  padding: 10px 20px;
  font-size: 14px;
  font-weight: 600;
  border-radius: 4px;
  cursor: pointer;
}

.modal-actions .btn-cancel {
  background: #333;
  color: #ccc;
  border: 1px solid #444;
}

.modal-actions .btn-cancel:hover { background: #444; }

.modal-actions .btn-delete {
  background: #991b1b;
  color: #fff;
  border: none;
}

.modal-actions .btn-delete:hover { background: #b91c1c; }

/* ------------------------------------------------------------------ */
/* WiFi mode section                                                  */
/* ------------------------------------------------------------------ */
.wifi-mode-section {
  margin-top: 12px;
  padding-top: 12px;
  border-top: 1px solid #333;
}

.wifi-mode-section > label {
  display: block;
  font-size: 13px;
  color: #aaa;
  margin-bottom: 10px;
}

.wifi-mode-buttons {
  display: flex;
  gap: 8px;
}

.btn-wifi-reset {
  padding: 6px 16px;
  font-size: 13px;
  font-weight: 600;
  background: #4a1515;
  color: #f87171;
  border: 1px solid #6b2020;
  border-radius: 4px;
  cursor: pointer;
  flex: 1;
}

.btn-wifi-reset:hover:not(:disabled) { background: #6b2020; }

.btn-wifi-reset:disabled {
  background: #333;
  color: #888;
  border-color: #444;
  cursor: default;
}

.main-header.standalone .header-title {
  border: 2px solid currentColor;
  border-radius: 6px;
  padding: 2px 14px;
}

/* AP mode notice */
.ap-notice {
  background: #1a1a2e;
  border-left: 3px solid #ffc107;
  padding: 10px 14px;
  border-radius: 4px;
  margin-bottom: 16px;
  font-size: 13px;
  color: #ddd;
}

/* ------------------------------------------------------------------ */
/* Footer                                                             */
/* ------------------------------------------------------------------ */
.main-footer {
  text-align: center;
  padding: 20px;
  font-size: 12px;
  color: #444;
}

/* ------------------------------------------------------------------ */
/* Card panels (kegs/profiles inside cards)                           */
/* ------------------------------------------------------------------ */
.card-panel {
  padding: 16px 20px;
  border-top: 1px solid #222;
}

/* ------------------------------------------------------------------ */
/* Manual keg weight input                                            */
/* ------------------------------------------------------------------ */
.keg-manual-input {
  width: 64px;
  padding: 6px 8px;
  font-size: 13px;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 4px;
  color: #e0e0e0;
}

/* ------------------------------------------------------------------ */
/* Gas type selector (profile readout)                                */
/* ------------------------------------------------------------------ */
.gas-select-row {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 10px;
}

.gas-label {
  font-size: 12px;
  color: #888;
  white-space: nowrap;
}

.gas-select {
  padding: 5px 8px;
  font-size: 12px;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 4px;
  color: #e0e0e0;
}

/* ------------------------------------------------------------------ */
/* Responsive                                                         */
/* ------------------------------------------------------------------ */
@media (max-width: 620px) {
  .multi-scale .scale-cards-row { flex-direction: column; }
  .multi-scale .scale-card .weight-value { font-size: 48px; }
  .multi-scale .scale-card .action-bar { padding: 12px 20px 8px; }
  .multi-scale .scale-card .unit-bar { padding: 4px 20px 12px; }
  .multi-scale .scale-card .card-panel { padding: 16px 20px; }
}

@media (max-width: 380px) {
  .weight-value { font-size: 48px; }
  .multi-scale .scale-card .weight-value { font-size: 36px; }
  .action-btn { padding: 12px; font-size: 14px; }
  .settings-tab-btn { padding: 8px 10px; font-size: 12px; }
}
